proof_block:
// Reveal every opaque spec fn the postcondition body transitively touches so
// z3 can see the relational equalities pinned by `next_get_request` and
// `host_state_common_postconditions`. (Re-revealing is idempotent.)
reveal(HostState::next_get_request_postconditions);
reveal(HostState::next_get_request_preconditions);
reveal(HostState::host_state_common_postconditions);
reveal(HostState::host_state_common_preconditions);
reveal(HostState::host_state_packet_preconditions);
reveal(HostState::valid);
reveal(Constants::valid);

// Prove the implication directly by case-splitting on its antecedent.
if post1_self_.next_get_request_postconditions(pre_self_, r1@)
    && post2_self_.next_get_request_postconditions(pre_self_, r2@)
{
    // Use the functional-uniqueness helper to expose the deterministically
    // pinned fields under both `r1` and `r2`. After these two calls Verus
    // knows: delegation_map / h / num_delegations / constants / received_packet
    // are all equal between the two runs.
    lemma_next_get_request_post_pinned_fields(pre_self_, post1_self_, r1@);
    lemma_next_get_request_post_pinned_fields(pre_self_, post2_self_, r2@);

    // Anchor shared `pre` quantities so triggers line up on identical syntactic
    // terms across the two runs.
    let pkt = pre_self_.received_packet.unwrap();
    let out1 = abstractify_seq_of_cpackets_to_set_of_sht_packets(r1@);
    let out2 = abstractify_seq_of_cpackets_to_set_of_sht_packets(r2@);

    // Re-assert each relational ensures-conjunct in the local context.
    assert(next_get_request(pre_self_@, post1_self_@, pkt@, out1));
    assert(next_get_request(pre_self_@, post2_self_@, pkt@, out2));
    assert(post1_self_.host_state_common_postconditions(pre_self_, pkt, r1@));
    assert(post2_self_.host_state_common_postconditions(pre_self_, pkt, r2@));

    // From `next_get_request`, the per-run posts inherit three fields from pre.
    assert(post1_self_@.delegation_map == pre_self_@.delegation_map);
    assert(post2_self_@.delegation_map == pre_self_@.delegation_map);
    assert(post1_self_@.delegation_map == post2_self_@.delegation_map);

    assert(post1_self_@.h == pre_self_@.h);
    assert(post2_self_@.h == pre_self_@.h);
    assert(post1_self_@.h == post2_self_@.h);

    assert(post1_self_@.num_delegations == pre_self_@.num_delegations);
    assert(post2_self_@.num_delegations == pre_self_@.num_delegations);
    assert(post1_self_@.num_delegations == post2_self_@.num_delegations);

    // From `host_state_common_postconditions`, constants are preserved.
    assert(post1_self_.constants == pre_self_.constants);
    assert(post2_self_.constants == pre_self_.constants);
    assert(post1_self_@.constants == pre_self_@.constants);
    assert(post2_self_@.constants == pre_self_@.constants);
    assert(post1_self_@.constants == post2_self_@.constants);

    // From `next_get_request_postconditions`, `received_packet is None` in
    // both runs, so the two abstract views agree on that field.
    assert(post1_self_.received_packet is None);
    assert(post2_self_.received_packet is None);
    assert(post1_self_@.received_packet is None);
    assert(post2_self_@.received_packet is None);
    assert(post1_self_@.received_packet == post2_self_@.received_packet);
}

helper_lemmas:
proof fn lemma_next_get_request_post_pinned_fields(
    pre: HostState,
    post: HostState,
    sent_packets: Seq<CPacket>,
)
    requires
        post.next_get_request_postconditions(pre, sent_packets),
    ensures
        pre.received_packet is Some,
        post.received_packet is None,
        post.constants == pre.constants,
        post@.delegation_map == pre@.delegation_map,
        post@.h == pre@.h,
        post@.num_delegations == pre@.num_delegations,
        post@.constants == pre@.constants,
        post@.received_packet is None,
        cpacket_seq_is_abstractable(sent_packets),
        next_get_request(
            pre@,
            post@,
            pre.received_packet.unwrap()@,
            abstractify_seq_of_cpackets_to_set_of_sht_packets(sent_packets),
        ),
{
    reveal(HostState::next_get_request_postconditions);
    reveal(HostState::next_get_request_preconditions);
    reveal(HostState::host_state_common_postconditions);
    reveal(HostState::host_state_common_preconditions);
    reveal(HostState::host_state_packet_preconditions);
}
